const { format } = require('../vendor/jsonfmt');

// report renders a record as PRETTY (2-space indented) JSON.
function report(obj) {
  return format(obj, { pretty: true });
}

function reportWrapped(obj) {
  return format({ wrapped: obj }, { pretty: true });
}

module.exports = { report, reportWrapped };

const { format } = require('../vendor/jsonfmt');

// summary renders a record as COMPACT (single-line) JSON.
function summary(obj) {
  return format(obj, { pretty: false });
}

function summaryWrapped(obj) {
  return format({ wrapped: obj }, { pretty: false });
}

module.exports = { summary, summaryWrapped };
